golden_sql:
["db.sales.aggregate([
  {
    $match: {
      saleDate: {
        $gte: ISODate('2017-01-01T00:00:00Z'),
        $lt: ISODate('2018-01-01T00:00:00Z')
      }
    }
  },
  {
    $unwind: '$items'
  },
  {
    $project: {
      storeLocation: 1,
      totalItemPrice: {
        $multiply: ['$items.price', '$items.quantity']
      }
    }
  },
  {
    $group: {
      _id: '$storeLocation',
      totalSales: {
        $sum: '$totalItemPrice'
      }
    }
  },
  {
    $project: {
      _id: 0,
      storeLocation: '$_id',
      totalSales: 1
    }
  }
])"]

["db.sales.aggregate([
  {
    $match: {
      saleDate: {
        $gte: ISODate('2017-01-01'),
        $lt: ISODate('2017-07-01')
      },
      'items.name': 'backpack'
    }
  },
  {
    $group: {
      _id: '$couponUsed',
      averageSatisfaction: { $avg: '$customer.satisfaction' }
    }
  },
  {
    $project: {
      _id: 0,
      couponUsed: '$_id',
      averageSatisfaction: 1
    }
  }
])"]

['db.sales.aggregate([
  {
    $match: {
      saleDate: {
        $gte: ISODate("2017-12-01T00:00:00.000Z"),
        $lt: ISODate("2018-01-01T00:00:00.000Z")
      }
    }
  },
  {
    $group: {
      _id: "$storeLocation",
      averageSatisfaction: { $avg: "$customer.satisfaction" }
    }
  },
  {
    $sort: { averageSatisfaction: -1 }
  },
  {
    $limit: 5
  },
  {
    $project: {
      _id: 0,
      storeLocation: "$_id",
      averageSatisfaction: 1
    }
  }
])']

['db.sales.aggregate([
