['db.sales.aggregate([
    {
        $match: {
            saleDate: {
                $gte: ISODate('2017-06-01T00:00:00Z'),
                $lte: ISODate('2017-08-31T23:59:59Z')
            }
        }
    },
    {
        $unwind: "$items"
    },
    {
        $match: {
            "items.tags": "electronics"
        }
    },
    {
        $group: {
