["db.sales.aggregate([
  {
    $match: {
      storeLocation: 'New York'
    }
  },
  {
    $addFields: {
      totalAmount: {
        $sum: {
          $map: {
            input: '$items',
            as: 'item',
            in: {
              $multiply: ['$$item.price', '$$item.quantity']
            }
          }
        }
      }
    }
  },
  {
    $match: {
      totalAmount: { $gt: 1000 }
    }
  },
  {
    $count: 'totalTransactions'
  }
])"]

