      }
    }
  },
  {
    $unwind: "$items"
  },
  {
    $group: {
      _id: "$_id",
      transactionTotal: {
        $sum: {
          $multiply: ["$items.price", "$items.quantity"]
        }
      }
    }
  },
  {
    $group: {
      _id: null,
      totalSales: {
        $sum: "$transactionTotal"
