['db.sales.aggregate([
  {
    $match: {
      saleDate: {
        $gte: ISODate('2017-12-01'),
        $lt: ISODate('2018-01-01')
      }
    }
  },
  {
    $group: {
      _id: "$storeLocation",
      totalSales: { $sum: 1 }
    }
  },
  {
    $sort: { totalSales: -1 }
  },
  {
    $limit: 1
  },
  {
    $project: { _id: 1 }
  },
  {
    $lookup: {
      from: "sales",
      let: { location: "$_id" },
      pipeline: [
        {
          $match: {
            saleDate: {
              $gte: ISODate('2017-12-01'),
              $lt: ISODate('2018-01-01')
            }
          }
        },
        {
          $match: {
            $expr: { $eq: ["$storeLocation", "$$location"] }
          }
        },
        {
          $unwind: "$items"
        },
        {
          $group: {
            _id: "$items.name",
            quantitySold: { $sum: "$items.quantity" }
          }
        },
        {
          $sort: { quantitySold: -1 }
        },
        {
          $limit: 10
        },
        {
          $project: {
            _id: 0,
            itemName: "$_id",
            quantitySold: 1
          }
        }
      ],
      as: "topItems"
    }
  },
  {
    $unwind: "$topItems"
  },
  {
    $replaceRoot: { newRoot: "$topItems" }
  }
]);']

['db.sales.aggregate([
  {
    $match: {
      couponUsed: true,
      saleDate: {
        $gte: ISODate('2017-12-01T00:00:00Z'),
        $lt: ISODate('2018-01-01T00:00:00Z')
      }
    }
  },
  {
    $unwind: "$items"
  },
  {
    $group: {
      _id: null,
      totalSalesVolume: {
        $sum: {
          $multiply: ["$items.price", "$items.quantity"]
        }
      }
    }
  },
  {
    $project: {
      _id: 0,
      totalSalesVolume: 1
    }
  }
])']
